#include <stdio.h>

int findMin(int *nums, int size) {
    int left = 0, right = size - 1;
    while (left < right) {
        int mid = left + (right - left) / 2;
        if (nums[mid] > nums[right])
            left = mid + 1;
        else
            right = mid;
    }
    return nums[left];
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int arr[100000];
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        printf("%d\n", findMin(arr, n));
    }
    return 0;
}

